body.content:
MainScheduler.ensureExecutingOnScheduler()

        if _running {
            return
        }

        _running = true
        repeat {
            guard let next = findNext() else {
                break
            }

            if _converter.compareVirtualTime(next.time, self.clock).greaterThan  {
                _clock = next.time
            }

            next.invoke()
            _schedulerQueue.remove(next)
        } while _running

        _running = false
